var e=[{id:`L3_1`,type:`dialog`,speaker:`MICKEY_MASON_NULL_NULL`,text:{KOREA:`이 자식들! 저항이 너무 심해!`,JPN:`こいつら！　抵抗が激しすぎるぞ！`,ENG:`Those bastards! They’re coming at us with everything they got!`,TWN:`這些傢伙，抵抗得很激烈呢！`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MICKEY_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`신경 쓰지 말고 빨리 빠져나가!`,JPN:`気にしないで、さっさと行け！`,ENG:`Forget about them and just get out of here!`,TWN:`別管了，趕快落跑吧！`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`저 엔진, 진짜로 얼마 못 버틴다!`,JPN:`あのエンジンじゃ、長くは持たないんだよ！`,ENG:`That engine's gonna blow any second now!`,TWN:`那個引擎真的撐不了多久了！`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`MICKEY_MASON_NULL_NULL`,text:{KOREA:`하지만 수가 너무 많아!`,JPN:`でも数が多すぎるんだ！`,ENG:`But there’s too many of them!`,TWN:`但是數量太多了！`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MICKEY_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`COMPUTER_VOICE_NULL_NULL`,text:{KOREA:`<color=#ffd34c>위험 경고. 주 엔진 과열.</color>`,JPN:`<color=#ffd34c>危険警告。主エンジン過熱。</color>`,ENG:`<color=#ffd34c>Warning. Main engine overheated.</color>`,TWN:`<color=#ffd34c>危險警告，主引擎過熱。</color>`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}},sfx:`FX_CUTSCEN_SIREN`},{id:`L10_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`빨리! 빨리 움직여!`,JPN:`早く！　早く動け！`,ENG:`Hurry! Get moving!`,TWN:`快點！快點動起來！`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`COMPUTER_VOICE_NULL_NULL`,text:{KOREA:`<color=#ffd34c>노심 손상. 폭발 위험 경고.</color>`,JPN:`<color=#ffd34c>炉心損傷。爆発危険警告。</color>`,ENG:`<color=#ffd34c>Reactor core damaged. Explosion imminent.</color>`,TWN:`<color=#ffd34c>核心受損，爆炸的危險警告。</color>`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`COMPUTER_VOICE_NULL_NULL`,text:{KOREA:`<color=#ffd34c>반응로 오버 플로우. 컨트롤 불능......</color>`,JPN:`<color=#ffd34c>反応炉オーバーフロー。コントロール不能……</color>`,ENG:`<color=#ffd34c>Reactor overflow. Losing control...</color>`,TWN:`<color=#ffd34c>反應爐溢出，無法控制……</color>`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`엎드려!!`,JPN:`伏せろ！！`,ENG:`Get down!`,TWN:`趴下！！`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};